module shift_register(
    input        clk,
    input        reset,
    input        load,
    input        data_in,
    input  [3:0] parallel_in,
    output [3:0] q
);

reg [3:0] shifted_q;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        shifted_q <= 4'b0000;
    end else if (load) begin
        shifted_q <= parallel_in;
    end else begin
        shifted_q <= {data_in, shifted_q[3:1]};
    end
end

assign q = shifted_q;

endmodule
